3	namespace HamptonHawksPlantSales.Infrastructure.Services.ImportAdapters;
4	
5	public sealed class HamptonHawks2026OrdersAdapter : ImportFormatAdapterBase
6	{
7	    public override ImportType Type => ImportType.Orders;
8	    public override string Name => "HamptonHawks2026Orders";
9	    public override bool IsCanonical => false;
10	    public override IReadOnlyList<string> RequiredHeaders { get; } = new[] { "Order #", "Name", "Item #", "Qnty" };
11	
12	    public override Dictionary<string, string> Map(Dictionary<string, string> rawRow)
13	    {
14	        var orderNumber = GetTrimmed(rawRow, "Order #");
15	        var name = GetTrimmed(rawRow, "Name");
16	        var phone = GetTrimmed(rawRow, "Phone");
17	        var email = GetTrimmed(rawRow, "Email");
18	        var seller = GetTrimmed(rawRow, "Seller");
19	        var sku = GetTrimmed(rawRow, "Item #");
20	        var qty = GetTrimmed(rawRow, "Qnty");
21	
22	        var (customerFirst, customerLast) = SplitOnFirstSpace(name);
23	        var (sellerFirst, sellerLast) = SplitOnFirstSpace(seller);
24	
25	        var canonical = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase)
26	        {
27	            ["OrderNumber"] = orderNumber,
28	            ["CustomerDisplayName"] = name,
29	            ["CustomerFirstName"] = customerFirst,
30	            ["CustomerLastName"] = customerLast,
31	            ["Phone"] = phone,
32	            ["Email"] = email,
33	            ["SellerDisplayName"] = seller,
34	            ["SellerFirstName"] = sellerFirst,
35	            ["SellerLastName"] = sellerLast,
36	            ["Sku"] = sku,
37	            ["QtyOrdered"] = qty,
38	            ["IsWalkUp"] = "false"
39	        };
40	
41	        return canonical;
42	    }
43	
44	    private static (string first, string last) SplitOnFirstSpace(string value)
45	    {
46	        if (string.IsNullOrWhiteSpace(value))
47	        {
48	            return (string.Empty, string.Empty);
49	        }
50	
51	        var trimmed = value.Trim();
52	        var idx = trimmed.IndexOf(' ');
53	        if (idx < 0)
54	        {
55	            return (trimmed, string.Empty);
