36	    /// <response code="200">Paged list of orders.</response>
37	    [HttpGet]
38	    [ProducesResponseType(typeof(ApiResponse<PagedResult<OrderResponse>>), 200)]
39	    public async Task<IActionResult> GetAll(
40	        [FromQuery] string? search,
41	        [FromQuery] OrderStatus? status,
42	        [FromQuery] bool? isWalkUp,
43	        [FromQuery] Guid? sellerId,
44	        [FromQuery] Guid? customerId,
45	        [FromQuery] bool includeDeleted = false,
