1	import { useEffect, useMemo, useState } from 'react';
2	import { useSearchParams } from 'react-router-dom';
3	import { plantsApi } from '@/api/plants.js';
4	import { LoadingSpinner } from '@/components/shared/LoadingSpinner.js';
5	import { ErrorBanner } from '@/components/shared/ErrorBanner.js';
6	import { PrintLayout } from '@/components/print/PrintLayout.js';
7	import { PlantLabel } from '@/components/print/PlantLabel.js';
8	import type { Plant } from '@/types/plant.js';
9	
10	type DensityMode = 'test' | 'sheet' | 'roll';
11	
12	type LabelPreset = {
13	  label: string;
14	  count: number;
15	};
16	
17	function isDensityMode(value: string | null): value is DensityMode {
18	  return value === 'test' || value === 'sheet' || value === 'roll';
19	}
20	
21	function parsePositiveInteger(value: string | null) {
22	  if (!value) return null;
23	  const parsed = Number.parseInt(value, 10);
24	  return Number.isFinite(parsed) && parsed > 0 ? parsed : null;
25	}
26	
27	function parseCsvValues(value: string) {
28	  return value
29	    .split(',')
30	    .map((entry) => entry.trim())
31	    .filter(Boolean);
32	}
33	
34	async function loadAllPlants() {
35	  const all: Plant[] = [];
36	  let page = 1;
37	  let totalPages = 1;
38	
39	  while (page <= totalPages) {
40	    const result = await plantsApi.list({ page, pageSize: 200 });
41	    all.push(...result.items);
42	    totalPages = result.totalPages;
43	    page += 1;
44	  }
45	
46	  return all;
47	}
48	
49	function buildPresetCounts(density: DensityMode, selectedPlantCount: number): LabelPreset[] {
50	  if (density === 'test') return [];
51	
52	  const minimumCount = Math.max(selectedPlantCount, 1);
53	  const baseCounts = density === 'sheet' ? [30, 60, 90] : [80, 160, 240];
54	  const unitLabel = density === 'sheet' ? 'sheet' : 'roll';
55	
56	  const presets: LabelPreset[] = [
57	    {
58	      label: selectedPlantCount > 1 ? `All selected (${minimumCount})` : '1 label',
59	      count: minimumCount,
60	    },
61	  ];
62	
63	  baseCounts.forEach((baseCount, index) => {
64	    const normalizedCount = Math.max(baseCount, minimumCount);
65	    const quantity = index + 1;
66	    presets.push({
67	      label: `${quantity} ${unitLabel}${quantity === 1 ? '' : 's'} (${normalizedCount})`,
68	      count: normalizedCount,
69	    });
70	  });
71	
72	  return presets;
73	}
74	
75	export function PrintPlantLabelsPage() {
76	  const [searchParams, setSearchParams] = useSearchParams();
77	  const [plants, setPlants] = useState<Plant[]>([]);
78	  const [loading, setLoading] = useState(true);
79	  const [error, setError] = useState<string | null>(null);
80	
81	  const densityParam = searchParams.get('density');
82	  const countParam = searchParams.get('count');
83	  const plantId = searchParams.get('plantId');
84	  const idsCsv = searchParams.get('ids') ?? '';
85	  const skuCsv = searchParams.get('skus') ?? '';
86	  const barcodeCsv = searchParams.get('barcodes') ?? '';
87	
88	  const requestedIds = useMemo(() => parseCsvValues(idsCsv), [idsCsv]);
89	  const requestedSkus = useMemo(() => parseCsvValues(skuCsv).map((value) => value.toLowerCase()), [skuCsv]);
90	  const requestedBarcodes = useMemo(() => parseCsvValues(barcodeCsv), [barcodeCsv]);
91	  const requestedLabelCount = parsePositiveInteger(countParam);
92	
93	  const requestedCount = (plantId ? 1 : 0) + requestedIds.length + requestedSkus.length + requestedBarcodes.length;
94	  const density: DensityMode = isDensityMode(densityParam) ? densityParam : requestedCount === 1 ? 'test' : 'sheet';
95	
96	  useEffect(() => {
97	    async function load() {
98	      setLoading(true);
99	      setError(null);
100	
101	      try {
102	        if (plantId) {
103	          const plant = await plantsApi.getById(plantId);
104	          setPlants([plant]);
105	          return;
106	        }
107	
108	        if (requestedIds.length > 0) {
109	          const requestedPlants = await Promise.all(
110	            requestedIds.map(async (requestedId) => {
111	              try {
112	                return await plantsApi.getById(requestedId);
113	              } catch {
114	                return null;
115	              }
116	            }),
117	          );
118	          setPlants(requestedPlants.filter((plant): plant is Plant => Boolean(plant)));
119	          return;
120	        }
121	
122	        if (requestedSkus.length === 0 && requestedBarcodes.length === 0) {
123	          const result = await plantsApi.list({ page: 1, pageSize: 24, activeOnly: true });
124	          setPlants(result.items);
125	          return;
126	        }
127	
128	        const inventory = await loadAllPlants();
129	        const bySku = new Map(inventory.map((plant) => [plant.sku.toLowerCase(), plant]));
130	        const byBarcode = new Map(inventory.map((plant) => [plant.barcode, plant]));
131	
132	        const matched = [
133	          ...requestedSkus.map((sku) => bySku.get(sku)).filter((plant): plant is Plant => Boolean(plant)),
134	          ...requestedBarcodes.map((barcode) => byBarcode.get(barcode)).filter((plant): plant is Plant => Boolean(plant)),
135	        ];
136	
137	        const deduped = Array.from(new Map(matched.map((plant) => [plant.id, plant])).values());
138	        setPlants(deduped);
139	      } catch (e) {
140	        setError(e instanceof Error ? e.message : 'Failed to load labels');
141	      } finally {
142	        setLoading(false);
143	      }
144	    }
145	
146	    void load();
147	  }, [plantId, requestedBarcodes, requestedIds, requestedSkus]);
148	
149	  const minimumLabelCount = useMemo(() => (density === 'test' ? 1 : Math.max(plants.length, 1)), [density, plants.length]);
150	
151	  const defaultLabelCount = useMemo(() => {
152	    if (plants.length === 0) return 0;
153	    if (density === 'test') return 1;
154	    const baseCount = density === 'sheet' ? 30 : 80;
155	    return Math.max(baseCount, minimumLabelCount);
156	  }, [density, minimumLabelCount, plants.length]);
157	
158	  const labelCount = density === 'test'
159	    ? 1
160	    : Math.max(requestedLabelCount ?? defaultLabelCount, minimumLabelCount);
161	
162	  const labelPresets = useMemo(() => buildPresetCounts(density, plants.length), [density, plants.length]);
163	
164	  const labelsToRender = useMemo(() => {
165	    if (plants.length === 0) return [];
166	    if (density === 'test') return plants.slice(0, 1);
167	
168	    return Array.from({ length: labelCount }, (_, index) => plants[index % plants.length]);
169	  }, [density, labelCount, plants]);
170	
171	  const densityHint = density === 'test'
172	    ? 'Single-label alignment test.'
173	    : density === 'sheet'
174	      ? 'Letter-sheet preview with labels laid out across full sheets.'
175	      : 'Thermal-roll preview with one label per printer page step.';
176	
177	  const printCss = useMemo(() => {
178	    const pageRule = density === 'sheet'
179	      ? '@page { size: letter portrait; margin: 0.35in; }'
180	      : '@page { size: 2in 1in; margin: 0; }';
181	
182	    const itemBreakRule = density === 'roll'
183	      ? '.label-roll-item { break-after: page; page-break-after: always; } .label-roll-item:last-child { break-after: auto; page-break-after: auto; }'
184	      : density === 'test'
185	        ? '.label-test-item { break-after: auto; page-break-after: auto; }'
186	        : '';
187	
188	    return `
189	      .plant-label-print-layout {
190	        max-width: 56rem;
191	      }
192	
193	      .label-sheet-preview {
194	        display: flex;
195	        flex-wrap: wrap;
196	        gap: 0.12in;
197	        width: min(100%, 6.5in);
198	        margin: 0 auto;
199	        justify-content: flex-start;
200	      }
201	
202	      .label-sheet-item {
203	        flex: 0 0 2in;
204	        width: 2in;
205	        display: flex;
206	        justify-content: center;
207	      }
208	
209	      .label-roll-preview,
210	      .label-test-preview {
211	        width: min(100%, 2.35in);
212	        margin: 0 auto;
213	        display: flex;
214	        flex-direction: column;
215	        align-items: center;
216	        gap: 0.18in;
217	      }
218	
219	      .label-roll-item,
220	      .label-test-item {
221	        width: 2in;
222	        display: flex;
223	        justify-content: center;
224	      }
225	
226	      @media print {
227	        ${pageRule}
228	
229	        .plant-label-print-layout {
230	          max-width: none !important;
231	          margin: 0 !important;
232	          padding: 0 !important;
233	        }
234	
235	        .label-sheet-preview,
236	        .label-roll-preview,
237	        .label-test-preview {
238	          margin: 0 auto;
239	        }
240	
241	        .label-sheet-preview {
242	          width: 6.5in;
243	          gap: 0.08in;
244	        }
245	
246	        .label-sheet-item {
247	          break-inside: avoid;
248	          page-break-inside: avoid;
249	        }
250	
251	        .label-roll-preview,
252	        .label-test-preview {
253	          width: 2in;
254	          gap: 0;
255	        }
256	
257	        .label-roll-item,
258	        .label-test-item {
259	          width: 2in;
260	        }
261	
262	        ${itemBreakRule}
263	      }
264	    `;
265	  }, [density]);
266	
267	  function updateDensity(nextDensity: DensityMode) {
268	    const next = new URLSearchParams(searchParams);
269	    next.set('density', nextDensity);
270	    setSearchParams(next, { replace: true });
271	  }
272	
273	  function updateLabelCount(nextValue: string) {
274	    const parsed = parsePositiveInteger(nextValue);
275	    if (!parsed) return;
276	
277	    const normalizedCount = Math.max(parsed, minimumLabelCount);
278	    const next = new URLSearchParams(searchParams);
279	    if (normalizedCount === defaultLabelCount) {
280	      next.delete('count');
281	    } else {
282	      next.set('count', String(normalizedCount));
283	    }
284	    setSearchParams(next, { replace: true });
285	  }
286	
287	  function applyPreset(count: number) {
288	    updateLabelCount(String(count));
289	  }
290	
291	  const backTo = plantId ? `/plants/${plantId}` : idsCsv ? '/plants' : '/imports';
292	  const previewClassName = density === 'sheet' ? 'label-sheet-preview' : density === 'roll' ? 'label-roll-preview' : 'label-test-preview';
293	  const itemClassName = density === 'sheet' ? 'label-sheet-item' : density === 'roll' ? 'label-roll-item' : 'label-test-item';
294	
295	  if (loading) return <LoadingSpinner message="Loading labels..." />;
296	  if (error) return <ErrorBanner message={error} />;
297	
298	  return (
299	    <PrintLayout backTo={backTo} className="plant-label-print-layout">
300	      <style>{printCss}</style>
301	
302	      <div className="no-print mb-4 rounded-md border border-gray-300 bg-gray-50 p-3">
303	        <h1 className="text-lg font-semibold text-gray-800">Plant Labels (1&quot; x 2&quot;)</h1>
304	        <div className="mt-2 flex flex-wrap items-center gap-4 text-sm">
305	          <span className="font-medium text-gray-700">Density:</span>
306	          {([
307	            { value: 'test', label: '1-up Test' },
308	            { value: 'sheet', label: 'Full Sheet (30)' },
309	            { value: 'roll', label: 'Full Roll (80)' },
310	          ] as { value: DensityMode; label: string }[]).map((option) => (
311	            <label key={option.value} className="inline-flex items-center gap-2 text-gray-700">
312	              <input
313	                type="radio"
314	                checked={density === option.value}
315	                onChange={() => updateDensity(option.value)}
316	              />
317	              {option.label}
318	            </label>
319	          ))}
320	        </div>
321	        {density !== 'test' && (
322	          <>
323	            <div className="mt-3 flex flex-wrap gap-2">
324	              {labelPresets.map((preset) => {
325	                const isActive = labelCount === preset.count;
326	                return (
327	                  <button
